def require_metrics_auth(f):
    """Decorator to protect the /metrics endpoint from unauthorized access."""

    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Check if metrics are enabled
        if not METRICS_ENABLED:
            return Response("Metrics endpoint is disabled", status=404)

        # IP-based access control
        client_ip = request.remote_addr
        if METRICS_ALLOWED_IPS and METRICS_ALLOWED_IPS != [""]:
            if client_ip not in METRICS_ALLOWED_IPS:
                return Response(
                    "Forbidden: IP not allowed", status=403
                )

        # Token-based authentication
        if METRICS_AUTH_TOKEN:
            auth_header = request.headers.get("Authorization", "")
            provided_token = None

            if auth_header.startswith("Bearer "):
                provided_token = auth_header[7:]
            else:
                provided_token = request.args.get("token")

            if provided_token != METRICS_AUTH_TOKEN:
                return Response(
                    "Unauthorized: Invalid or missing authentication token",
                    status=401,
                )

        return f(*args, **kwargs)

    return decorated_function


