@app.before_request
def before_request():
    """Record request start time and increment in-progress gauge."""
    g.start_time = time.time()
    # Normalize endpoint to avoid high cardinality
    endpoint = _normalize_endpoint(request.path)
    REQUESTS_IN_PROGRESS.labels(method=request.method, endpoint=endpoint).inc()

    # Track request size
    content_length = request.content_length or 0
    REQUEST_SIZE.labels(method=request.method, endpoint=endpoint).observe(
        content_length
    )


@app.after_request
def after_request(response):
    """Record request metrics after processing."""
    if hasattr(g, "start_time"):
        latency = time.time() - g.start_time
        endpoint = _normalize_endpoint(request.path)

        # Record latency
        REQUEST_LATENCY.labels(method=request.method, endpoint=endpoint).observe(
            latency
        )
        REQUEST_LATENCY_SUMMARY.labels(
            method=request.method, endpoint=endpoint
        ).observe(latency)

        # Record request count with status
        REQUEST_COUNT.labels(
            method=request.method,
            endpoint=endpoint,
            http_status=response.status_code,
        ).inc()

        # Decrement in-progress gauge
        REQUESTS_IN_PROGRESS.labels(method=request.method, endpoint=endpoint).dec()

        # Track response size
        response_size = response.content_length or len(response.get_data())
        RESPONSE_SIZE.labels(method=request.method, endpoint=endpoint).observe(
            response_size
        )

    # Update uptime gauge
    APP_UPTIME.set(time.time() - APP_START_TIME)

    return response


@app.errorhandler(Exception)
def handle_exception(e):
    """Track exceptions in metrics."""
    endpoint = _normalize_endpoint(request.path)
    REQUEST_EXCEPTIONS.labels(
        method=request.method,
        endpoint=endpoint,
        exception_type=type(e).__name__,
    ).inc()

    # Decrement in-progress if it was incremented
    if hasattr(g, "start_time"):
        REQUESTS_IN_PROGRESS.labels(method=request.method, endpoint=endpoint).dec()

    return jsonify({"error": "Internal Server Error"}), 500


def _normalize_endpoint(path):
    """Normalize endpoint paths to prevent high cardinality.

    This prevents metric explosion from dynamic URL segments like /users/12345.
    """
    # Map known patterns to normalized forms
    import re

    patterns = [
        (r"/users/\d+", "/users/:id"),
        (r"/orders/\d+", "/orders/:id"),
        (r"/products/\d+", "/products/:id"),
        (r"/api/v\d+/", "/api/v:version/"),
    ]

    normalized = path
    for pattern, replacement in patterns:
        normalized = re.sub(pattern, replacement, normalized)

    return normalized


