# Custom Metric Registration Helper
# ============================================================

class MetricsManager:
    """Helper class for managing custom metrics programmatically."""

    _counters = {}
    _gauges = {}
    _histograms = {}

    @classmethod
    def increment_counter(cls, name, labels=None, amount=1):
        """Increment a counter metric."""
        if name in cls._counters:
            if labels:
                cls._counters[name].labels(**labels).inc(amount)
            else:
                cls._counters[name].inc(amount)

    @classmethod
    def set_gauge(cls, name, value, labels=None):
        """Set a gauge metric value."""
        if name in cls._gauges:
            if labels:
                cls._gauges[name].labels(**labels).set(value)
            else:
                cls._gauges[name].set(value)

    @classmethod
    def observe_histogram(cls, name, value, labels=None):
        """Observe a value in a histogram metric."""
        if name in cls._histograms:
            if labels:
                cls._histograms[name].labels(**labels).observe(value)
            else:
                cls._histograms[name].observe(value)

    @classmethod
    def register_counter(cls, name, description, label_names=None):
        """Register a new counter metric."""
        counter = Counter(name, description, label_names or [])
        cls._counters[name] = counter
        return counter

    @classmethod
    def register_gauge(cls, name, description, label_names=None):
        """Register a new gauge metric."""
        gauge = Gauge(name, description, label_names or [])
        cls._gauges[name] = gauge
        return gauge

    @classmethod
    def register_histogram(cls, name, description, label_names=None, buckets=None):
        """Register a new histogram metric."""
        kwargs = {}
        if buckets:
            kwargs["buckets"] = buckets
        histogram = Histogram(name, description, label_names or [], **kwargs)
        cls._histograms[name] = histogram
        return histogram


